// Barrel for the BTKbd atom.

export 'kbd.types.dart';
export 'kbd.widget.dart';

/// Padding mode for [BTKbd].
///
/// - [text] — horizontal padding only (for key labels like "Ctrl", "⌘")
/// - [icon] — equal padding on all sides (for symbol/arrow keys like "↑")
enum BTKbdVariant { text, icon }

/// BTKbd — keyboard key badge.
///
/// Displays a single keyboard key in a styled pill. Use [BTKbdGroup] to render
/// a horizontal shortcut combo.
///
/// ## Usage:
/// ```dart
/// // Single key
/// const BTKbd(label: '⌘')
/// const BTKbd(label: 'Ctrl')
/// BTKbd(label: 'K', dark: true)
///
/// // Arrow / symbol key (equal padding)
/// const BTKbd(label: '↑', variant: BTKbdVariant.icon)
///
/// // Shortcut combo
/// BTKbdGroup(keys: ['⌘', 'K'])
/// BTKbdGroup(keys: ['Ctrl', 'Shift', 'P'])
/// BTKbdGroup(keys: ['⌘', 'Z'], dark: true)
/// ```
library;

import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/kbd/kbd.types.dart';
import 'package:flutter/material.dart';

class BTKbd extends StatelessWidget {
  const BTKbd({
    required this.label,
    this.variant = BTKbdVariant.text,
    this.dark = false,
    super.key,
  });

  /// The key label to display (e.g. '⌘', 'Ctrl', '↑').
  final String label;

  /// Padding mode — [BTKbdVariant.text] for labels,
  /// [BTKbdVariant.icon] for symbols.
  final BTKbdVariant variant;

  /// Dark background variant. Defaults to false (light).
  final bool dark;

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;

    final bg = dark ? const Color(0xFF3C4450) : colors.bg.subtle;
    final fg = dark ? colors.text.tertiary : colors.text.secondary;

    final padding = variant == BTKbdVariant.icon
        ? EdgeInsets.all(2.0)
        : EdgeInsets.symmetric(horizontal: 2.0);

    return Container(
      constraints: BoxConstraints(minWidth: 16.0, minHeight: 16.0),
      padding: padding,
      decoration: BoxDecoration(
        color: bg,
        borderRadius: BorderRadius.circular(4.0),
      ),
      child: Text(
        label,
        textAlign: TextAlign.center,
        style: TextStyle(
          fontFamily: BTTypography.fontFamily,
          fontSize: 10.0,
          fontWeight: FontWeight.w700,
          height: 1.6,
          letterSpacing: 0,
          color: fg,
        ),
      ),
    );
  }
}

// ── Group ────────────────────────────────────────────────────────────────────

class BTKbdGroup extends StatelessWidget {
  const BTKbdGroup({
    required this.keys,
    this.variant = BTKbdVariant.text,
    this.dark = false,
    super.key,
  });

  /// The key labels to display in sequence.
  final List<String> keys;

  /// Padding mode applied to every key in the group.
  final BTKbdVariant variant;

  /// Dark variant applied to every key in the group.
  final bool dark;

  @override
  Widget build(BuildContext context) {
    return Wrap(
      spacing: 2,
      runSpacing: 2,
      crossAxisAlignment: WrapCrossAlignment.center,
      children: keys
          .map(
            (k) => BTKbd(label: k, variant: variant, dark: dark),
          )
          .toList(),
    );
  }
}
